// SPDX-License-Identifier: UNLICENSED
pragma solidity ^0.8.27;

import {Enum} from "@safe-global/safe-smart-account/contracts/libraries/Enum.sol";

contract SafeMock {
    mapping(address => bool) private _owners;
    uint256 private _threshold = 1;

    function addOwner(address owner) external {
        _owners[owner] = true;
    }

    function isOwner(address owner) external view returns (bool) {
        return _owners[owner];
    }

    function setThreshold(uint256 threshold) external {
        _threshold = threshold;
    }

    function getThreshold() external view returns (uint256) {
        return _threshold;
    }

    /// @dev Mirrors Safe.execTransaction. Skips signature verification.
    ///      Propagates reverts so BalanceProxy errors bubble up in tests.
    function execTransaction(
        address to,
        uint256 value,
        bytes memory data,
        Enum.Operation operation,
        uint256,
        uint256,
        uint256,
        address,
        address payable,
        bytes memory
    ) external payable returns (bool success) {
        require(operation == Enum.Operation.Call, "SafeMock: only Call");
        bytes memory returnData;
        (success, returnData) = to.call{value: value}(data);
        if (!success) {
            assembly {
                revert(add(returnData, 0x20), mload(returnData))
            }
        }
    }

    receive() external payable {}
}

contracts/SafeRouter.sol.content:
// SPDX-License-Identifier: UNLICENSED
pragma solidity ^0.8.27;

import {IBalanceProxy} from "./interfaces/IBalanceProxy.sol";
import {BalanceMetadata} from "./interfaces/IMetadata.sol";
import {IERC20Metadata} from "@openzeppelin/contracts/token/ERC20/extensions/IERC20Metadata.sol";
import {SafeCast} from "@openzeppelin/contracts/utils/math/SafeCast.sol";
import {ISafe} from "@safe-global/safe-smart-account/contracts/interfaces/ISafe.sol";
import {Enum} from "@safe-global/safe-smart-account/contracts/libraries/Enum.sol";

/// @title SafeRouter
/// @notice Safe-periphery for routing the final Safe execution through clear signing.
///
/// @dev The SafeRouter is added as a Safe owner without increasing the Safe
///      threshold. Human owners sign the original Safe transaction in Safe UI.
///      The final executor signs this wrapper on a hardware wallet. The router
///      then supplies its own Safe owner slot as a prevalidated signature and
///      executes the original Safe transaction atomically with balance checks.
contract SafeRouter {
    bytes4 private constant INVALID_EIP1271_MAGIC_VALUE = 0xffffffff;

    IBalanceProxy public immutable balanceProxy;

    struct SafeTx {
        address to;
        uint256 value;
        bytes data;
        Enum.Operation operation;
        uint256 safeTxGas;
        uint256 baseGas;
        uint256 gasPrice;
        address gasToken;
        address payable refundReceiver;
        bytes signatures;
        uint256 routerSigPosition;
    }

    error NotSafeOwner(address caller, address safe);
    error RouterNotSafeOwner(address router, address safe);
    error SafeExecutionFailed(address safe, address target);
    error InvalidSignaturesLength(uint256 length);
    error InvalidRouterSignaturePosition(uint256 position, uint256 signatureCount);
    error InsufficientSafeSignatures(uint256 providedWithRouter, uint256 threshold);
    error MetadataBalancesLengthMismatch(uint256 metaLength, uint256 balancesLength);
    error InvalidMetadata(
        address token,
        string expectedSymbol,
        uint8 expectedDecimals,
        string actualSymbol,
        uint8 actualDecimals
    );

    constructor(IBalanceProxy balanceProxy_) {
        balanceProxy = balanceProxy_;
    }

    /// @notice Contract signatures must not validate outside this wrapper flow.
    /// @dev SafeRouter uses Safe's prevalidated-signature path (`v == 1`)
    ///      instead of EIP-1271 contract signatures (`v == 0`).
    function isValidSignature(bytes32, bytes memory) external pure returns (bytes4) {
        return INVALID_EIP1271_MAGIC_VALUE;
    }

    /// @notice Execute original Safe tx, then verify absolute post-balances.
    function safeExecuteWithPostBalances(
        ISafe safe,
        IBalanceProxy.Balance[] calldata postBalances,
        SafeTx calldata safeTx
    ) external {
        _verifySafeContext(safe);
        _execOriginalTx(safe, safeTx);
        _verifyPostBalances(postBalances);
    }

    /// @notice Execute original Safe tx, then verify balance diffs for this tx.
    function safeExecuteWithDiffs(
        ISafe safe,
        IBalanceProxy.Balance[] calldata diffs,
        SafeTx calldata safeTx
    ) external {
        _verifySafeContext(safe);
        uint256[] memory beforeBalances = _snapshotBalances(diffs);
        _execOriginalTx(safe, safeTx);
        _verifyDiffs(diffs, beforeBalances);
    }

    /// @notice Metadata variant for hardware-wallet clear signing.
    function safeExecuteWithPostBalancesMeta(
        ISafe safe,
        BalanceMetadata[] calldata meta,
        IBalanceProxy.Balance[] calldata postBalances,
        SafeTx calldata safeTx
    ) external {
        _checkMetadata(meta, postBalances);
        _verifySafeContext(safe);
        _execOriginalTx(safe, safeTx);
        _verifyPostBalances(postBalances);
    }

    /// @notice Metadata variant for hardware-wallet clear signing.
    function safeExecuteWithDiffsMeta(
        ISafe safe,
        BalanceMetadata[] calldata meta,
        IBalanceProxy.Balance[] calldata diffs,
        SafeTx calldata safeTx
    ) external {
        _checkMetadata(meta, diffs);
        _verifySafeContext(safe);
        uint256[] memory beforeBalances = _snapshotBalances(diffs);
        _execOriginalTx(safe, safeTx);
        _verifyDiffs(diffs, beforeBalances);
    }

    function _verifySafeContext(ISafe safe) internal view {
        if (!safe.isOwner(msg.sender)) revert NotSafeOwner(msg.sender, address(safe));
        if (!safe.isOwner(address(this))) {
            revert RouterNotSafeOwner(address(this), address(safe));
        }
    }

    function _execOriginalTx(ISafe safe, SafeTx calldata safeTx) internal {
        bytes memory signatures = _buildSignatures(
            safeTx.signatures,
            safeTx.routerSigPosition,
            safe.getThreshold()
        );

        bool success = safe.execTransaction(
            safeTx.to,
            safeTx.value,
            safeTx.data,
            safeTx.operation,
            safeTx.safeTxGas,
            safeTx.baseGas,
            safeTx.gasPrice,
            safeTx.gasToken,
            safeTx.refundReceiver,
            signatures
        );
        if (!success) revert SafeExecutionFailed(address(safe), safeTx.to);
    }

    /// @dev Delegates absolute post-balance verification to BalanceProxy.
    ///      address(0), empty data, and zero msg.value trigger checks-only mode.
    function _verifyPostBalances(IBalanceProxy.Balance[] calldata postBalances) internal {
        balanceProxy.proxyCall(
            postBalances,
            new IBalanceProxy.Approval[](0),
            address(0),
            "",
            new IBalanceProxy.Balance[](0)
        );
    }

    function _snapshotBalances(
        IBalanceProxy.Balance[] calldata balances
    ) internal view returns (uint256[] memory snapshot) {
        snapshot = new uint256[](balances.length);
        for (uint256 i = 0; i < balances.length; i++) {
            snapshot[i] = _currentBalance(balances[i].token, balances[i].target);
        }
    }

    function _verifyDiffs(
        IBalanceProxy.Balance[] calldata diffs,
        uint256[] memory beforeBalances
    ) internal view {
        for (uint256 i = 0; i < diffs.length; i++) {
            uint256 afterBalance = _currentBalance(diffs[i].token, diffs[i].target);
            int256 actualDiff = _signedDiff(afterBalance, beforeBalances[i]);
            if (actualDiff < diffs[i].balance) {
                revert IBalanceProxy.ERC8009BalanceDiffConstraintViolation(
                    diffs[i].token,
                    diffs[i].target,
                    diffs[i].balance,
                    actualDiff
                );
            }
        }
    }

    function _currentBalance(
        address token,
        address who
    ) internal view returns (uint256) {
        return token == address(0)
            ? who.balance
            : IERC20Metadata(token).balanceOf(who);
    }

    function _signedDiff(
        uint256 afterBalance,
        uint256 beforeBalance
    ) internal pure returns (int256) {
        if (afterBalance >= beforeBalance) {
            return SafeCast.toInt256(afterBalance - beforeBalance);
        }
        return -SafeCast.toInt256(beforeBalance - afterBalance);
    }

    function _checkMetadata(
        BalanceMetadata[] calldata meta,
        IBalanceProxy.Balance[] calldata balances
    ) internal view {
        if (meta.length != balances.length) {
            revert MetadataBalancesLengthMismatch(meta.length, balances.length);
        }
        for (uint256 i = 0; i < meta.length; i++) {
            string memory actualSymbol;
            uint8 actualDecimals;
            if (balances[i].token == address(0)) {
                actualSymbol = "ETH";
                actualDecimals = 18;
            } else {
                actualSymbol = IERC20Metadata(balances[i].token).symbol();
                actualDecimals = IERC20Metadata(balances[i].token).decimals();
            }
            if (
                keccak256(abi.encodePacked(actualSymbol)) !=
                keccak256(abi.encodePacked(meta[i].symbol)) ||
                actualDecimals != meta[i].decimals
            ) {
                revert InvalidMetadata(
                    balances[i].token,
                    meta[i].symbol,
                    meta[i].decimals,
                    actualSymbol,
                    actualDecimals
                );
            }
        }
    }

    /// @dev Inserts SafeRouter's prevalidated Safe signature (`v == 1`).
    ///      Existing signatures are expected to be sorted Safe signatures with
    ///      the router slot excluded. If existing signatures already satisfy the
    ///      Safe threshold, the router signature may be outside the checked
    ///      prefix; the wrapper still supplies the clear-signing checks.
    function _buildSignatures(
        bytes calldata existingSigs,
        uint256 routerSigPosition,
        uint256 threshold
    ) internal view returns (bytes memory) {
        if (existingSigs.length % 65 != 0) {
            revert InvalidSignaturesLength(existingSigs.length);
        }

        uint256 existingCount = existingSigs.length / 65;
        if (routerSigPosition > existingCount) {
            revert InvalidRouterSignaturePosition(routerSigPosition, existingCount);
        }
        if (existingCount + 1 < threshold) {
            revert InsufficientSafeSignatures(existingCount + 1, threshold);
        }

        bytes memory routerSig = abi.encodePacked(
            bytes32(uint256(uint160(address(this)))),
            bytes32(0),
            uint8(1)
        );

        return abi.encodePacked(
            existingSigs[:routerSigPosition * 65],
            routerSig,
            existingSigs[routerSigPosition * 65:]
        );
    }
}

